# -*- coding: utf-8 -*-
"""Handler for /guide command."""

from __future__ import annotations

import logging

from .base import BaseControlCommandHandler, ControlContext
from ..guidance import (
    add_guidance,
    clear_guidance,
    is_guide_mode,
    pending_count,
    set_guide_mode,
)

logger = logging.getLogger(__name__)


class GuideCommandHandler(BaseControlCommandHandler):
    """Add non-interrupting guidance to the currently running task.

    Usage:
        /guide <text>      # Add one guidance note
        /guide on          # Turn guide mode on
        /guide off         # Turn guide mode off
        /guide status      # Show status
        /guide clear       # Clear pending notes
    """

    command_name = "/guide"

    async def _current_status(
        self,
        context: ControlContext,
    ) -> tuple[str | None, str]:
        workspace = context.workspace
        channel_id = context.channel.channel
        chat_manager = getattr(workspace, "chat_manager", None)
        if chat_manager is None:
            return None, "idle"
        chat_id = await chat_manager.get_chat_id_by_session(
            context.session_id,
            channel_id,
        )
        if chat_id is None:
            return None, "idle"
        status = await workspace.task_tracker.get_status(chat_id)
        return chat_id, status

    def _agent_id(self, context: ControlContext) -> str:
        return context.agent_id or getattr(context.workspace, "agent_id", "")

    def _usage(self) -> str:
        return (
            "**Guide Mode**\n\n"
            "- `/guide <内容>`：把这段内容作为当前任务的引导，不打断任务。\n"
            "- `/guide on`：开启引导模式。任务运行时，后续普通消息会被当作引导注入。\n"
            "- `/guide off`：关闭引导模式。\n"
            "- `/guide status`：查看模式、任务和待注入引导状态。\n"
            "- `/guide clear`：清空尚未被 Agent 吸收的引导。\n"
            "\n别名：`/g <内容>`。"
        )

    async def handle(self, context: ControlContext) -> str:
        raw_args = str(context.args.get("_raw_args") or "").strip()
        command_text, _, trailing_text = raw_args.partition("\n")
        command, _, inline_text = command_text.strip().partition(" ")
        command = command.lower()
        extra_text = "\n".join(
            part for part in (inline_text.strip(), trailing_text.strip()) if part
        )
        agent_id = self._agent_id(context)

        if not raw_args or command in {"help", "-h", "--help"}:
            return self._usage()

        if command in {"on", "enable", "start"}:
            set_guide_mode(agent_id, context.session_id, True)
            _, status = await self._current_status(context)
            parts = [
                "**Guide Mode On**",
                (
                    "Guide mode is enabled. While the current task is "
                    "running, normal messages will be injected as guidance.\n"
                    "Tip: Use `/g <内容>` as a shortcut to inject guidance directly."
                ),
            ]
            if status not in ("idle", "done", "", None):
                parts.append(f"Current task status: `{status}`")
            return "\n".join(parts)

        if command in {"off", "disable", "stop"}:
            set_guide_mode(agent_id, context.session_id, False)
            return "**Guide Mode Off**\nGuide mode is disabled. Normal messages will start a new task as usual."

        if command == "status":
            enabled = is_guide_mode(agent_id, context.session_id)
            count = pending_count(agent_id, context.session_id)
            chat_id, status = await self._current_status(context)
            lines = [
                "**Guide Status**",
                f"- Guide mode: {'ON' if enabled else 'OFF'}",
                f"- Pending guidance: {count} item(s)",
                f"- Task status: `{status or 'idle'}`",
            ]
            if chat_id:
                lines.append(f"- Chat ID: `{chat_id}`")
            return "\n".join(lines)

        if command == "clear":
            removed = clear_guidance(agent_id, context.session_id)
            return f"**Cleared** {removed} pending guidance item(s)."

        content_to_guide = raw_args
        if extra_text:
            content_to_guide = extra_text
        count = add_guidance(
            agent_id,
            context.session_id,
            content_to_guide,
            channel=context.channel.channel,
            user_id=context.user_id or "",
        )
        return f"Guidance queued ({count} total). The current task will pick it up on next step.\n\n_Use `/guide clear` to remove pending guidance, `/guide off` to disable guide mode._"


class GuideAliasCommandHandler(GuideCommandHandler):
    """Short alias: /g"""

    command_name = "/g"


class ChineseGuideAliasCommandHandler(GuideCommandHandler):
    """Chinese alias: /引导"""

    command_name = "/引导"
